def test_get_username():
    client = DatabaseClient()
    fake_user = {'id': 42, 'name': 'Alice'}

    with patch.object(client, 'fetch_user', return_value=fake_user) as mock_fetch:
        result = get_username(client, 42)

    assert result == 'Alice'
    mock_fetch.assert_called_once_with(42)

