from unittest.mock import MagicMock
import pytest

def retry_fetch(client, url):
    try:
        return client.get(url)
    except ConnectionError:
        return client.get(url)

def test_retry_fetch_recovers_after_connection_error():
    fake_response = MagicMock(status_code=200)
    mock_client = MagicMock()
    mock_client.get.side_effect = [ConnectionError('timeout'), fake_response]

    result = retry_fetch(mock_client, 'https://api.example.com/data')

    assert result.status_code == 200
    assert mock_client.get.call_count == 2

